1	interface QuoteItem {
2	  type: string;
3	  damage: number;
4	  cursed?: boolean;
5	  enchantment?: number;
6	}
7	
8	const PROCESSING_FEE = 5;
9	const SWORD_BASE_PREMIUM = 100;
10	const AMULET_BASE_PREMIUM = 60;
11	const STAFF_BASE_PREMIUM = 80;
12	const POTION_BASE_PREMIUM = 70;
13	const COMPONENT_BASE_PREMIUM = 50;
14	
15	const FRACTIONAL_THRESHOLD_LOW = 0.45;
16	const FRACTIONAL_THRESHOLD_HIGH = 0.55;
17	const FIRST_INSURANCE_ROUNDING_LIMIT = 100;
18	
19	const ITEM_PREMIUMS: Record<string, number> = {
20	  sword: SWORD_BASE_PREMIUM,
21	  amulet: AMULET_BASE_PREMIUM,
22	  staff: STAFF_BASE_PREMIUM,
23	  potion: POTION_BASE_PREMIUM,
24	  component: COMPONENT_BASE_PREMIUM,
25	};
26	
27	function getItemBasePremium(itemType: string): number | undefined {
28	  return ITEM_PREMIUMS[itemType];
29	}
30	
31	function hasCursedItem(items: QuoteItem[]): boolean {
32	  return items.some(item => item.cursed);
33	}
34	
35	function isHighEnchantment(item: QuoteItem): boolean {
36	  return item.enchantment !== undefined && item.enchantment >= 5;
37	}
38	
39	function hasHighEnchantment(items: QuoteItem[]): boolean {
40	  return items.some(isHighEnchantment);
41	}
42	
43	function shouldApplyMultiItemHighPremiumFee(items: QuoteItem[], maxPremium: number): boolean {
44	  return items.length > 1 && maxPremium >= 100;
45	}
46	
47	function calculateProcessingFee(items: QuoteItem[]): number {
48	  const hasEnchanted = hasHighEnchantment(items);
49	  const hasCursed = hasCursedItem(items);
50	
51	  // Enchanted items without curse: no processing fee
52	  if (hasEnchanted && !hasCursed) {
53	    return 0;
54	  }
55	
56	  // Cursed items without enchantment: increased fee
57	  if (hasCursed && !hasEnchanted) {
58	    return 10;
59	  }
60	
61	  // Check for multi-item high premium surcharge
62	  const maxPremium = Math.max(...items.map(item => getItemBasePremium(item.type) ?? 0));
63	  if (shouldApplyMultiItemHighPremiumFee(items, maxPremium)) {
64	    return PROCESSING_FEE + 10;
65	  }
66	
67	  return PROCESSING_FEE;
68	}
69	
70	function calculateItemPremium(item: QuoteItem): number {
71	  const basePremium = getItemBasePremium(item.type);
72	  if (basePremium === undefined) {
73	    throw new Error(`Unknown item type: ${item.type}`);
74	  }
75	  let premium = basePremium;
76	  if (item.cursed) {
77	    premium += basePremium * 0.5;
78	  }
79	  if (isHighEnchantment(item)) {
80	    premium += basePremium * 0.3;
81	  }
82	  return premium;
83	}
84	
85	function applyLongStandingCustomerDiscount(total: number, yearsAsCustomer?: number): number {
86	  if (yearsAsCustomer !== undefined && yearsAsCustomer >= 2) {
87	    return total * 0.8;
88	  }
89	  return total;
90	}
91	
92	function applyFirstInsuranceSurcharge(total: number, isFirstInsurance?: boolean): number {
93	  if (isFirstInsurance) {
94	    return total * 1.1;
95	  }
96	  return total;
97	}
98	
99	function applyFollowUpContractDiscount(total: number, isFollowUpContract?: boolean): number {
100	  if (isFollowUpContract) {
101	    return Math.floor(total * 0.85);
102	  }
103	  return total;
104	}
105	
106	function applyFirstInsuranceRoundingAdjustment(total: number, isFirstInsurance?: boolean): number {
107	  const rounded = Math.ceil(total);
108	  const fractional = total % 1;
109	
110	  // Mid-range decimals (0.45-0.55) are subject to special rounding for first insurance
111	  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
112	  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
113	  const shouldApplyExtraRound = isFirstInsurance && hasMidRangeDecimal && isLowValue;
114	
115	  if (shouldApplyExtraRound) {
116	    return rounded + 1;
117	  }
118	
119	  return rounded;
120	}
121	
122	interface QuoteOptions {
123	  yearsAsCustomer?: number;
124	  yearsWithMHPCO?: number;
125	  isFirstInsurance?: boolean;
126	  isFollowUpContract?: boolean;
127	}
128	
129	function applyQuoteModifiers(total: number, options?: QuoteOptions): number {
130	  // Apply modifiers in sequence: discount -> surcharge -> discount -> rounding
131	  const yearsAsCustomer = options?.yearsAsCustomer ?? options?.yearsWithMHPCO;
132	  let modifiedTotal = applyLongStandingCustomerDiscount(total, yearsAsCustomer);
133	  modifiedTotal = applyFirstInsuranceSurcharge(modifiedTotal, options?.isFirstInsurance);
134	  modifiedTotal = applyFollowUpContractDiscount(modifiedTotal, options?.isFollowUpContract);
135	  return applyFirstInsuranceRoundingAdjustment(modifiedTotal, options?.isFirstInsurance);
136	}
137	
138	export function createQuote(items: unknown[], options?: QuoteOptions): number {
139	  const quoteItems = items as QuoteItem[];
140	  if (quoteItems.length === 0) {
141	    return PROCESSING_FEE;
142	  }
143	
144	  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
145	  const fee = calculateProcessingFee(quoteItems);
146	  const baseTotal = totalPremium + fee;
147	
148	  return applyQuoteModifiers(baseTotal, options);
149	}
150	
151	interface ClaimPolicy {
152	  items: QuoteItem[];
153	  coverage: number;
154	}
155	
156	interface Damage {
157	  type: string;
158	  amount: number;
159	}
160	
161	const DEDUCTIBLE = 100;
162	
163	export function processClaim(policy: ClaimPolicy, damage: Damage): number {
164	  if (damage.amount <= DEDUCTIBLE) {
165	    return 0;
166	  }
167	  return Math.min(damage.amount - DEDUCTIBLE, policy.coverage * 2);
168	}
