export function processClaim(policy: ClaimPolicy, damage: Damage): number {
  if (damage.amount <= DEDUCTIBLE) {
    return 0;
  }

  const damageItem = policy.items.find(item => item.type === damage.type);
  const hasHighEnchantment = damageItem && damageItem.enchantment !== undefined && damageItem.enchantment >= 5;

  const cap = hasHighEnchantment ? policy.coverage * 3 : policy.coverage * 2;
  return Math.min(damage.amount - DEDUCTIBLE, cap);
}

